-							if (
-								getUpdateDirection(update, counter) ===
-								wrongDirection
-							) {
-								report(node);
-							}
-						} else if (
-							update.type === "AssignmentExpression" &&
-							getAssignmentDirection(update, counter) ===
-								wrongDirection
+						if (
+							update.type === "SequenceExpression"
+								? update.expressions.some(
